def build_cai_weights(codon_usage):
    w = {}
    for aa, lst in codon_usage.items():
        if not lst:
            continue
        max_f = max(freq for codon, freq in lst)
        if max_f <= 0:
            continue
        for codon, freq in lst:
            w[codon] = (freq / max_f) if freq > 0 else 0.0
    return w


def cai(seq, include_stop=False, on_unknown="raise"):
    if not isinstance(seq, str):
        raise TypeError("seq must be a string")

    s = seq.strip().upper().replace(" ", "").replace("\n", "")
    if not s:
        return 0.0

    s = s.replace("T", "U")
    weights = build_cai_weights(CODON_USAGE)

    logs = []
    L = 0

    n = len(s) - (len(s) % 3)
    for i in range(0, n, 3):
        codon = s[i:i+3]
        if not include_stop and codon in ("UAA", "UAG", "UGA"):
            continue

        w = weights.get(codon)
        if w is None:
            if on_unknown == "raise":
                raise ValueError(f"Unknown codon '{codon}' at position {i//3 + 1}")
            if on_unknown == "skip":
                continue
            if on_unknown == "zero":
                return 0.0

        if w <= 0:
            return 0.0

        logs.append(math.log(w))
        L += 1

    if L == 0:
        return 0.0

    return math.exp(sum(logs) / L)


