prefix = "TTTATAATTTCTTCTTCCAGAA"  # IRES=22
suffix = "UUAAGCUA"

beam = 500
iters = 10
lr = 0.03
L = 2.5


def exec_cmd(props, input_text, cwd="./"):
    proc = subprocess.run(
        props, input=input_text + "\n", cwd=cwd,
        capture_output=True, text=True, check=True)
    out_lines = proc.stdout.splitlines()
    err_lines = proc.stderr.splitlines()
    return "\n".join(out_lines + err_lines).split("\n")


def find(lines, q):
    for l in lines:
        if q in l:
            return l.split(":")[1].strip()
    return None


def colored_ires(seq, start, color=31):
    return f"\033[1;{color}m{seq[0:start]}\033[m{seq[start+1:]}"


def count_cross_pairs(s: str, k: int):
    stack = []
    cross = 0
    for i, c in enumerate(s):
        if c == '(':
            stack.append(i)
        elif c == ')':
            j = stack.pop()
            cross += (j <= k) != (i <= k)
    return cross


def EFE(seq):
    res = exec_cmd([
        "./tools/LinearPartition/linearpartition", "-V", "-d0", "-b0"
    ], seq, "./")
    val = find(res, "Free Energy")
    return float(val.split(' ')[0])


def EnsembleWrapper(seq, init, eps, ires_end=0, lam=0.1):
    params = ["./bin/EnsembleDesign"]
    params += list(map(str, [beam, iters, lr, eps, 1, init]))
    params += ["--prefix", prefix, "--suffix",
               suffix, "--iresEND", str(ires_end),
               "--lambda", str(lam)]
    res = exec_cmd(params, seq, "./")
    mrna = find(res, "Final mRNA")
    print(" ".join(params))

    res = exec_cmd(["RNAfold", "--noPS"], mrna, "./")
    struct = res[1].split(" ")[0]

    crp = count_cross_pairs(struct, 22)

    print(f" - mRNA:  {colored_ires(mrna, 22)}")
    print(f"          {colored_ires(res[1], 22)}")
    print(f"   CROSS: {crp}  [for {ires_end}]")

    return crp, mrna, struct


def frange(start, stop, step):
    x = start
    while x <= stop + 1e-12:
        yield x
        x += step


def main():
    parser = argparse.ArgumentParser(
        description="Faster subset of test-random.py with the same output format.")
    parser.add_argument("--per_set", type=int, default=10,
                        help="How many proteins to take from each set (default: 10).")
    parser.add_argument("--eps_step", type=float, default=0.2,
                        help="Epsilon step for frange(0.0, 1.0, step) (default: 0.2).")
    parser.add_argument("--lambda_value", type=float, default=0.1,
                        help="Lambda passed to EnsembleDesign (default: 0.1).")
    parser.add_argument("--output", type=str, default="",
                        help="Optional output file path; default: test_lite_<timestamp>.txt")
    args = parser.parse_args()

    ts = datetime.now().strftime("%Y%m%d_%H%M%S")
    out_path = args.output if args.output else f"test_lite_{ts}.txt"
    res = open(out_path, 'w')
    res.write("sid\tires\tEps\tLength\tCrosspairs\tCAI\tEFE\tmRNA\tStruct\n")

    sid = 1
    for eps in frange(0.0, 1.0, args.eps_step):
        for set_name in data:
            subset = data[set_name][:args.per_set]
            for seq in subset:
                tmp = exec_cmd([
                    "./bin/LinearDesign_2D", f"{L:.2f}", "0", "codon_usage_freq_table_human.csv"
                ], seq, "./tools/LinearDesign/")
                init = find(tmp, "mRNA sequence")
                for ires_end in [0, 22]:
                    crp, mrna, struct = EnsembleWrapper(seq, init, eps, ires_end, args.lambda_value)
                    cai_val = cai(mrna)
                    efe = EFE(mrna)
                    result_line = (
                        f"{sid}\t{ires_end}\t{eps:.1f}\t{len(seq)}\t{crp}\t"
                        f"{cai_val:.3f}\t{efe:.3f}\t{mrna}\t{struct}"
                    )
                    print(result_line)
                    res.write(result_line + "\n")
                sid += 1

    res.close()
    print(f"Saved results to: {out_path}")


if __name__ == "__main__":
    main()
